import { defineComponentStyle } from "@yamada-ui/react"

export const hStackStyle = defineComponentStyle({
  base: {
    alignItems: "center",
    gap: "md",
  },
})

export type HStackStyle = typeof hStackStyle

import { a11y, page, render } from "#test/browser"
import { Box } from "../box"
import { HStack } from "./h-stack"

const TestComponent = () => (
  <HStack data-testid="h-stack">
    <Box>HStack Item</Box>
  </HStack>
)

describe("<HStack />", () => {
  test("renders component correctly", async () => {
    await a11y(<TestComponent />)
  })

  test("sets `displayName` correctly", () => {
    expect(HStack.displayName).toBe("StackHorizontal")
  })

  test("sets `className` correctly", async () => {
    await render(<TestComponent />)
    await expect
      .element(page.getByTestId("h-stack"))
      .toHaveClass("ui-stack--horizontal")
  })

  test("renders HTML tag correctly", async () => {
    await render(<TestComponent />)
    expect(page.getByTestId("h-stack").element().tagName).toBe("DIV")
  })

  test("renders h-stack correctly", async () => {
    await render(<TestComponent />)

    await expect
      .element(page.getByTestId("h-stack"))
      .toHaveStyle({ flexDirection: "row" })
  })
})

"use client"

import type { ThemeProps, WithoutThemeProps } from "@yamada-ui/react"
import type { HStackStyle } from "./h-stack.style"
import type { StackProps } from "./stack"
import { createComponent } from "@yamada-ui/react"
import { hStackStyle } from "./h-stack.style"
import { Stack } from "./stack"

export interface HStackProps
  extends WithoutThemeProps<StackProps, HStackStyle>, ThemeProps<HStackStyle> {}

const {
  PropsContext: HStackPropsContext,
  usePropsContext: useHStackPropsContext,
  withContext,
} = createComponent<HStackProps, HStackStyle>("stack--horizontal", hStackStyle)

export { HStackPropsContext, useHStackPropsContext }

/**
 * `HStack` is a component that groups elements and provides space between child elements.
 *
 * @see https://yamada-ui.com/docs/components/stack
 */
export const HStack = withContext<"div", HStackProps>(Stack)(undefined, {
  direction: "row",
})

import { defineComponentStyle } from "@yamada-ui/react"

export const stackStyle = defineComponentStyle({
  base: {
    display: "flex",
    gap: "lg",
  },
})

export type StackStyle = typeof stackStyle

import type { FC } from "react"
import { useEffect, useState } from "react"
import { a11y, page, render } from "#test/browser"
import { Box } from "../box"
import { Flex } from "../flex"
import { Separator } from "../separator"
import { Stack } from "./stack"

describe("<Stack />", () => {
  test("renders component correctly", async () => {
    await a11y(
      <Stack>
        <Box>Stack Item</Box>
      </Stack>,
    )
  })

  test("sets `displayName` correctly", () => {
    expect(Stack.displayName).toBe("Stack")
  })

  test("sets `className` correctly", async () => {
    await render(
      <Stack data-testid="stack">
        <Box>Stack Item</Box>
      </Stack>,
    )
    await expect.element(page.getByTestId("stack")).toHaveClass("ui-stack")
  })

  test("renders HTML tag correctly", async () => {
    await render(
      <Stack data-testid="stack">
        <Box>Stack Item</Box>
      </Stack>,
    )
    expect(page.getByTestId("stack").element().tagName).toBe("DIV")
  })

  test("renders all the allowed shorthand style props", async () => {
    await render(
      <Stack
        data-testid="stack"
        align="stretch"
        direction="row"
        justify="start"
        wrap="nowrap"
      >
        <Box>Stack Item</Box>
      </Stack>,
    )

    await expect.element(page.getByTestId("stack")).toHaveStyle({
      alignItems: "stretch",
      flexDirection: "row",
      flexWrap: "nowrap",
      justifyContent: "start",
    })
  })

  const data = [
    { name: "孫悟空" },
    { name: "ベジータ" },
    { name: "フリーザ" },
    { name: "ナッパ" },
    { name: "クリリン" },
    { name: "ギニュー" },
  ]

  interface ComponentProps {
    name?: string
    onUnmount?: (name: string) => void
  }

  const Component: FC<ComponentProps> = ({ name, onUnmount }) => {
    useEffect(() => {
      return () => {
        if (name && onUnmount) onUnmount(name)
      }
    }, [])

    return <Flex data-testid="character">{name}</Flex>
  }

  test("renders list of items correctly", async () => {
    await render(
      <Stack>
        {data.map(({ name }) => (
          <Component key={name} name={name} />
        ))}
      </Stack>,
    )

    await expect
      .poll(() => page.getByTestId("character").elements().length)
      .toBe(6)
  })

  test("renders list of items with provided keys when cloning children", async () => {
    const unMountMock = vi.fn()

    const Wrapper = ({ data }: { data: { [key: string]: string }[] }) => {
      const [characters, setCharacters] = useState(data)

      return (
        <>
          <Box
            data-testid="delete-button"
            onClick={() => setCharacters((prev) => prev.slice(1))}
          >
            delete character
          </Box>

          <Stack separator={<Separator />}>
            {characters.map(({ name }) => (
              <Component key={name} name={name} onUnmount={unMountMock} />
            ))}
          </Stack>
        </>
      )
    }

    const { user } = await render(<Wrapper data={data} />)

    await expect
      .poll(() => page.getByTestId("character").elements().length)
      .toBe(6)
    expect(unMountMock).not.toHaveBeenCalled()

    await user.click(page.getByTestId("delete-button"))
    await expect.poll(() => unMountMock.mock.calls.length).toBe(1)
    expect(unMountMock).toHaveBeenCalledExactlyOnceWith("孫悟空")
  })
})

"use client"

import type { ReactElement } from "react"
import type { CSSProps, HTMLStyledProps } from "@yamada-ui/react"
import type { StackStyle } from "./stack.style"
import { cloneElement, Fragment, useMemo } from "react"
import { createComponent, styled, replaceObject, useValidChildren } from "@yamada-ui/react"
import { stackStyle } from "./stack.style"

export interface StackProps extends Omit<HTMLStyledProps, "direction"> {
  /**
   * The CSS `align-items` property.
   */
  align?: CSSProps["alignItems"]
  /**
   * The CSS `flex-direction` property.
   */
  direction?: CSSProps["flexDirection"]
  /**
   * The CSS `justify-content` property.
   */
  justify?: CSSProps["justifyContent"]
  /**
   * If `true`, each stack item will show a separator.
   */
  separator?: ReactElement
  /**
   * The CSS `flex-wrap` property.
   */
  wrap?: CSSProps["flexWrap"]
}

const {
  PropsContext: StackPropsContext,
  usePropsContext: useStackPropsContext,
  withContext,
} = createComponent<StackProps, StackStyle>("stack", stackStyle)

export { StackPropsContext, useStackPropsContext }

/**
 * `Stack` is a component that groups elements and provides space between child elements.
 *
 * @see https://yamada-ui.com/docs/components/stack
 */
export const Stack = withContext<"div", StackProps>(
  ({
    align: alignItems,
    children,
    direction: flexDirection = "column",
    justify: justifyContent,
    separator,
    wrap: flexWrap,
    ...rest
  }) => {
    const isColumn = (value: any) =>
      value === "column" || value === "column-reverse"

    const validChildren = useValidChildren(children)
    const cloneChildren = useMemo(
      () =>
        separator
          ? validChildren.map((child, index) => {
              const key = typeof child.key !== "undefined" ? child.key : index

              const cloneSeparator = cloneElement<any>(separator, {
                borderWidth: replaceObject(flexDirection, (value) =>
                  isColumn(value) ? "0 0 1px 0" : "0 0 0 1px",
                ),
                h: replaceObject(flexDirection, (value) =>
                  isColumn(value) ? "fit-content" : "100%",
                ),
                w: replaceObject(flexDirection, (value) =>
                  isColumn(value) ? "100%" : "fit-content",
                ),
              })

              return (
                <Fragment key={key}>
                  {index ? cloneSeparator : null}
                  {child}
                </Fragment>
              )
            })
          : validChildren,
      [separator, flexDirection, validChildren],
    )

    return (
      <styled.div
        alignItems={alignItems}
        flexDirection={flexDirection}
        flexWrap={flexWrap}
        justifyContent={justifyContent}
        {...rest}
      >
        {cloneChildren}
      </styled.div>
    )
  },
)()

import { defineComponentStyle } from "@yamada-ui/react"

