"use client"

import type { ThemeProps, WithoutThemeProps } from "@yamada-ui/react"
import type { StackProps } from "./stack"
import type { VStackStyle } from "./v-stack.style"
import { createComponent } from "@yamada-ui/react"
import { Stack } from "./stack"
import { vStackStyle } from "./v-stack.style"

export interface VStackProps
  extends WithoutThemeProps<StackProps, VStackStyle>, ThemeProps<VStackStyle> {}

const {
  PropsContext: VStackPropsContext,
  usePropsContext: useVStackPropsContext,
  withContext,
} = createComponent<VStackProps, VStackStyle>("stack--vertical", vStackStyle)

export { useVStackPropsContext, VStackPropsContext }

/**
 * `VStack` is a component that groups elements and provides space between child elements.
 *
 * @see https://yamada-ui.com/docs/components/stack
 */
export const VStack = withContext<"div", VStackProps>(Stack)(undefined, {
  direction: "column",
})

import { defineComponentStyle } from "@yamada-ui/react"

export const zStackStyle = defineComponentStyle({
  base: {
    gap: "lg",
    overflow: "hidden",
    position: "relative",
  },
})

export type ZStackStyle = typeof zStackStyle

import { page, render } from "#test/browser"
import { Box } from "../box"
import { ZStack } from "./z-stack"

describe("<ZStack />", () => {
  test("sets `displayName` correctly", () => {
    expect(ZStack.displayName).toBe("StackDepth")
  })

  test("sets `className` correctly", async () => {
    await render(
      <ZStack data-testid="z-stack">
        <Box>ZStack Item</Box>
      </ZStack>,
    )

    const zStack = page.getByTestId("z-stack")

    await expect.element(zStack).toHaveClass("ui-stack--depth")
  })

  test("renders HTML tag correctly", async () => {
    await render(
      <ZStack data-testid="z-stack">
        <Box>ZStack Item</Box>
      </ZStack>,
    )

    const zStack = page.getByTestId("z-stack")
    expect(zStack.element().tagName).toBe("DIV")
  })

  test("startIndex property works correctly", async () => {
    await render(
      <ZStack startIndex={10}>
        <Box>ZStack Item</Box>
      </ZStack>,
    )

    const zStack = page.getByText("ZStack Item")
    await expect.element(zStack).toHaveStyle({ zIndex: "10" })
  })

  test("Child elements are correctly overlaid and rendered", async () => {
    await render(
      <ZStack>
        <Box>Item 1</Box>
        <Box>Item 2</Box>
      </ZStack>,
    )

    const item1 = page.getByText("Item 1")
    const item2 = page.getByText("Item 2")

    await expect.element(item1).toHaveStyle({ position: "absolute" })
    await expect.element(item2).toHaveStyle({ position: "absolute" })
  })

  test("Whether the direction is working properly", async () => {
    await render(
      <ZStack direction="center-end">
        <Box>Item 1</Box>
        <Box>Item 2</Box>
      </ZStack>,
    )

    const item1 = page.getByText("Item 1")
    const item2 = page.getByText("Item 2")

    await expect.element(item1).toHaveStyle({
      position: "absolute",
      zIndex: "0",
    })
    await expect.element(item2).toHaveStyle({
      position: "absolute",
      zIndex: "1",
    })
  })

  test("Whether the reverse is working properly", async () => {
    await render(
      <ZStack reverse>
        <Box>Item 1</Box>
        <Box>Item 2</Box>
      </ZStack>,
    )

    const item1 = page.getByText("Item 1")
    const item2 = page.getByText("Item 2")

    await expect.element(item1).toHaveStyle({
      position: "absolute",
      zIndex: "0",
    })
    await expect.element(item2).toHaveStyle({
      position: "absolute",
      zIndex: "1",
    })
  })

  test("applies correct styles with direction set to start", async () => {
    await render(
      <ZStack direction="start">
        <Box>Box 1</Box>
        <Box>Box 2</Box>
      </ZStack>,
    )

    const box1 = page.getByText("Box 1")
    const box2 = page.getByText("Box 2")

    await expect.element(box1).toHaveStyle({
      left: "0",
      position: "absolute",
      zIndex: "0",
    })
    await expect.element(box2).toHaveStyle({
      left: "0",
      position: "absolute",
      zIndex: "1",
    })
  })

  test("applies correct styles with direction set to center-start", async () => {
    await render(
      <ZStack direction="center-start">
        <Box>Box 1</Box>
        <Box>Box 2</Box>
      </ZStack>,
    )

    const box1 = page.getByText("Box 1")
    const box2 = page.getByText("Box 2")

    await expect.element(box1).toHaveStyle({
      position: "absolute",
      top: "0",
      zIndex: "0",
    })
    await expect.element(box2).toHaveStyle({
      position: "absolute",
      top: "0",
      zIndex: "1",
    })
  })
})

"use client"

import type { RefObject } from "react"
import type {
  CSSObject,
  Direction,
  HTMLStyledProps,
  ThemeProps,
} from "@yamada-ui/react"
import type { ZStackStyle } from "./z-stack.style"
import {
  cloneElement,
  createRef,
  Fragment,
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState,
} from "react"
import { createComponent,
  mergeCSS,
  styled,
  useInjectVarsIntoCss,
  useInjectVarsIntoProps, getValidChildren, mergeRefs } from "@yamada-ui/react"
import { zStackStyle } from "./z-stack.style"

export interface ZStackProps
  extends Omit<HTMLStyledProps, "direction">, ThemeProps<ZStackStyle> {
  /**
   * Stack in the specified direction.
   *
   * @default 'end'
   */
  direction?: Direction
  /**
   * If `true`, calculate the `width` and `height` of the element and assign container.
   *
   * @default true
   */
  fit?: boolean
  /**
   * If `true`, reverse direction.
   *
   * @default false
   */
  reverse?: boolean
  /**
   * If set the stack will start from the given index.
   *
   * @default 0
   */
  startIndex?: number
}

const {
  PropsContext: ZStackPropsContext,
  usePropsContext: useZStackPropsContext,
  withContext,
} = createComponent<ZStackProps, ZStackStyle>("stack--depth", zStackStyle)

export { useZStackPropsContext, ZStackPropsContext }

/**
 * `ZStack` is a component that groups elements and provides space between child elements.
 *
 * @see https://yamada-ui.com/docs/components/stack
 */
export const ZStack = withContext<"div", ZStackProps>(
  ({
    css,
    children,
    direction = "end",
    fit = true,
    reverse = false,
    startIndex = 0,
    ...rest
  }) => {
    if (direction === "start-center") direction = "start"
    if (direction === "end-center") direction = "end"

    const refMap = useRef<Map<number, RefObject<HTMLDivElement | null>>>(
      new Map(),
    )
    const [rect, setRect] = useState<{ height: number; width: number }>({
      height: 0,
      width: 0,
    })

    const vertical = useCallback(
      (space: string) => {
        if (direction.startsWith("start")) {
          return { [!reverse ? "bottom" : "top"]: space }
        } else if (direction.startsWith("end")) {
          return { [!reverse ? "top" : "bottom"]: space }
        } else {
          return { [!reverse ? "top" : "bottom"]: 0 }
        }
      },
      [direction, reverse],
    )

    const horizontal = useCallback(
      (space: string) => {
        if (direction.endsWith("-start")) {
          return { [!reverse ? "right" : "left"]: space }
        } else if (direction.endsWith("-end")) {
          return { [!reverse ? "left" : "right"]: space }
        } else {
          return { [!reverse ? "left" : "right"]: 0 }
        }
      },
      [direction, reverse],
    )

    const cloneChildren = useMemo(() => {
      const validChildren = getValidChildren(children)

      const clonedChildren = validChildren.map((child, index) => {
        const ref = createRef<HTMLDivElement>()

        refMap.current.set(index, ref)

        const key = child.key ?? index

        const zIndex = startIndex + index
        const space = `calc({space} * ${index})`

        const css: CSSObject = {
          position: "absolute",
          zIndex,
          ...vertical(space),
          ...horizontal(space),
        }

        const props = {
          ...child.props,
          ref: mergeRefs(child.props.ref, ref),
          css: mergeCSS(child.props.css, css),
        }

        const clonedChild = cloneElement(child, props)

        return <Fragment key={key}>{clonedChild}</Fragment>
      })

      return clonedChildren
    }, [children, startIndex, vertical, horizontal])

    useEffect(() => {
      if (!fit) return

      let negativeLeft = direction.endsWith("-start")
      let negativeTop = direction.startsWith("start")
      let width = 0
      let height = 0

      if (reverse) {
        negativeLeft = !negativeLeft
        negativeTop = !negativeTop
      }

      for (const ref of refMap.current.values()) {
        if (!ref.current) continue

        let { offsetHeight, offsetLeft, offsetParent, offsetTop, offsetWidth } =
          ref.current

        if (!offsetParent && process.env.NODE_ENV !== "test") continue

        if (negativeLeft) {
          const offsetParentWidth =
            (offsetParent as HTMLDivElement | null)?.offsetWidth ?? 0

          offsetLeft = offsetParentWidth - offsetLeft - offsetWidth
        }

        if (negativeTop) {
          const offsetParentHeight =
            (offsetParent as HTMLDivElement | null)?.offsetHeight ?? 0

          offsetTop = offsetParentHeight - offsetTop - offsetHeight
        }

        offsetWidth += offsetLeft
        offsetHeight += offsetTop

        if (offsetWidth > width) width = offsetWidth
        if (offsetHeight > height) height = offsetHeight
      }

      setRect({ height, width })
    }, [cloneChildren, direction, reverse, fit])

    return (
      <styled.div
        css={css}
        minHeight={fit ? `${rect.height}px` : undefined}
        minWidth={fit ? `${rect.width}px` : undefined}
        {...rest}
      >
        {cloneChildren}
      </styled.div>
    )
  },
)(undefined, (props) => {
  const css = useInjectVarsIntoCss(props.css, { gap: "space" })
  const rest = useInjectVarsIntoProps(props, { gap: "space" })

  return { ...rest, css }
})
